import{_ as e,o,c as a,a2 as r}from"./chunks/framework.c3r8iWL8.js";const m=JSON.parse('{"title":"SOP-008: Post-Incident & Regression Loop","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"sops/SOP-008-post-incident.md","filePath":"sops/SOP-008-post-incident.md","lastUpdated":1782929962000}'),s={name:"sops/SOP-008-post-incident.md"};function i(d,t,n,l,p,c){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="sop-008-post-incident-regression-loop" tabindex="-1">SOP-008: Post-Incident &amp; Regression Loop <a class="header-anchor" href="#sop-008-post-incident-regression-loop" aria-label="Permalink to &quot;SOP-008: Post-Incident &amp; Regression Loop&quot;">​</a></h1><p><strong>Version:</strong> 1.0 · <strong>Owner:</strong> SRE + Developer · <strong>Gate:</strong> G5</p><h2 id="purpose-scope" tabindex="-1">Purpose &amp; scope <a class="header-anchor" href="#purpose-scope" aria-label="Permalink to &quot;Purpose &amp; scope&quot;">​</a></h2><p>Close the quality feedback loop: postmortem, mandatory regression artifacts, and updates to spec/ADR when needed.</p><h2 id="roles" tabindex="-1">Roles <a class="header-anchor" href="#roles" aria-label="Permalink to &quot;Roles&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Role</th><th>RACI</th></tr></thead><tbody><tr><td>SRE</td><td><strong>A</strong> — postmortem process</td></tr><tr><td>DEV</td><td>R — regression test PR</td></tr><tr><td>ARCH</td><td>C — ADR updates</td></tr><tr><td>PO</td><td>C — spec amendments</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Sev-1 or Sev-2 incident resolved (SOP-007)</li><li>Incident ticket with timeline</li></ul><h2 id="procedure" tabindex="-1">Procedure <a class="header-anchor" href="#procedure" aria-label="Permalink to &quot;Procedure&quot;">​</a></h2><ol><li><strong>Schedule blamesless postmortem</strong> — Within 48h for Sev-1; 5 business days for Sev-2.</li><li><strong>AI draft postmortem</strong> — From ticket + logs + deploy history; human edits all sections.</li><li><strong>Identify gaps</strong> — Classify: test gap, spec gap, ADR gap, monitoring gap, process gap.</li><li><strong>Create action items</strong> — Each with owner and due date in ticket.</li></ol><h3 id="mandatory-artifacts-by-gap-type" tabindex="-1">Mandatory artifacts (by gap type) <a class="header-anchor" href="#mandatory-artifacts-by-gap-type" aria-label="Permalink to &quot;Mandatory artifacts (by gap type)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Gap</th><th>Required action</th><th>Due</th></tr></thead><tbody><tr><td>Test gap</td><td>Regression test PR merged</td><td>48h (Sev-1), 5 days (Sev-2)</td></tr><tr><td>Monitoring gap</td><td>New alert or baseline update</td><td>5 days</td></tr><tr><td>Spec gap</td><td>SOP-003 amendment PR</td><td>5 days</td></tr><tr><td>ADR gap</td><td>SOP-002 new/supersede ADR</td><td>10 days</td></tr><tr><td>Process gap</td><td>SOP update PR</td><td>10 days</td></tr></tbody></table><ol start="5"><li><strong>Regression test</strong> — AI drafts from incident; DEV reviews; must fail on reproduced condition pre-fix.</li><li><strong>Publish postmortem</strong> — Internal wiki + link from Backstage service page.</li><li><strong>Verify closure</strong> — SRE confirms all action items done before incident closed.</li></ol><h2 id="definition-of-done" tabindex="-1">Definition of Done <a class="header-anchor" href="#definition-of-done" aria-label="Permalink to &quot;Definition of Done&quot;">​</a></h2><ul><li>[ ] Postmortem published</li><li>[ ] Regression test merged (Sev-1/2)</li><li>[ ] Monitoring/spec/ADR actions tracked to completion</li><li>[ ] Incident ticket closed</li></ul><h2 id="related-sops" tabindex="-1">Related SOPs <a class="header-anchor" href="#related-sops" aria-label="Permalink to &quot;Related SOPs&quot;">​</a></h2><ul><li><a href="./SOP-007-incident-response.html">SOP-007</a> · <a href="./SOP-002-adr-lifecycle.html">SOP-002</a> · <a href="./SOP-003-spec-approval.html">SOP-003</a></li></ul>',17)])])}const g=e(s,[["render",i]]);export{m as __pageData,g as default};
